#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
int MAP[51][51]={0};
int n,m,flag[21]={0},maxx=0;
void dfs(int cur,int sum){
    flag[cur]=1;int ff=0;
    for(int i=1;i<=n;i++){
        if(flag[i]==1)continue;
        if(MAP[cur][i]){ff=1;dfs(i,sum+MAP[cur][i]);flag[i]=0;}
    }if(!ff){maxx=max(maxx,sum);}return;
}int main(void){
    cin>>n>>m;
    for(int k=1,t1,t2;k<=m;k++){
         cin>>t1>>t2,cin>>MAP[t1][t2],MAP[t2][t1]=MAP[t1][t2];
    }for(int i=1;i<=n;++i){
        memset(flag,0,sizeof(flag));dfs(i,0);
    }cout<<maxx;
    return false;
}
